39	
40	      return db
41	        .select({
42	          installationId: gatewayTokens.installationId,
43	          tokenId: gatewayTokens.id,
44	          encryptedRefreshToken: gatewayTokens.refreshToken,
45	          expiresAt: gatewayTokens.expiresAt,
46	          provider: gatewayInstallations.provider,
47	          externalId: gatewayInstallations.externalId,
48	          orgId: gatewayInstallations.orgId,
49	        })
50	        .from(gatewayTokens)
51	        .innerJoin(
52	          gatewayInstallations,
53	          eq(gatewayTokens.installationId, gatewayInstallations.id)
54	        )
55	        .where(
56	          and(
57	            eq(gatewayInstallations.status, "active"),
58	            isNotNull(gatewayTokens.refreshToken),
59	            isNotNull(gatewayTokens.expiresAt),
60	            lt(gatewayTokens.expiresAt, cutoff)
61	          )
62	        );
63	    });
64	
65	    log.info("tokens expiring soon", {
66	      count: expiringSoon.length,
67	    });
68	
69	    // -- Step 2: Refresh each token -----------------------------------------
70	    let refreshedCount = 0;
71	
72	    for (const row of expiringSoon) {
73	      await step.run(`refresh-${row.installationId}`, async () => {
74	        const providerName = row.provider as SourceType;
75	        const providerDef = getProvider(providerName);
76	
77	        if (!providerDef) {
78	          return;
79	        }
80	
81	        const auth = providerDef.auth;
82	        if (auth.kind !== "oauth" || !auth.refreshToken) {
83	          // Provider doesn't support token refresh — skip
84	          return;
85	        }
86	
87	        const config = providerConfigs[providerName];
88	
89	        if (!config) {
90	          log.warn("provider not configured — skipping", {
91	            provider: providerName,
92	            installationId: row.installationId,
93	          });
94	          return;
95	        }
96	
97	        try {
98	          const decryptedRefresh = await decrypt(
99	            row.encryptedRefreshToken!,
100	            getEncryptionKey()
101	          );
102	          const refreshed = await auth.refreshToken(
103	            config as never,
104	            decryptedRefresh
105	          );
106	          await updateTokenRecord(
107	            row.tokenId,
108	            refreshed,
109	            row.encryptedRefreshToken,
110	            row.expiresAt
111	          );
112	
113	          refreshedCount++;
114	          log.info("token refreshed", {
115	            installationId: row.installationId,
116	            provider: providerName,
117	          });
118	        } catch (err) {
119	          // Refresh failure is logged but not fatal — the request-time refresh
120	          // path in getActiveTokenForInstallation() is the fallback.
121	          log.warn("refresh failed", {
122	            installationId: row.installationId,
123	            provider: providerName,
124	            error: parseError(err),
125	          });
126	        }
127	      });
128	    }
129	
130	    return { refreshed: refreshedCount };
131	  }
132	);

1	import { db } from "@db/app/client";
2	import { gatewayTokens } from "@db/app/schema";
3	import { encrypt } from "@repo/app-encryption";
4	import type { OAuthTokens } from "@repo/app-providers";
5	import { eq } from "@vendor/db";
6	import { parseError } from "@vendor/observability/error/next";
7	import { log } from "@vendor/observability/log/next";
8	import { getEncryptionKey } from "./encryption";
9	
10	/**
11	 * Write an encrypted token record for an installation.
12	 * Used after OAuth code exchange.

1	/**
2	 * Connection lifecycle (teardown) function
3	 *
4	 * Ported from apps/gateway/src/workflows/connection-teardown.ts
5	 *
6	 * KEY CHANGES vs gateway service:
7	 * - Upstash Workflow context.run() → Inngest step.run()
8	 * - Function ID: platform/connection.lifecycle
9	 * - Trigger: platform/connection.lifecycle event (was Upstash Workflow trigger)
10	 * - Cancel backfill: fires Inngest event instead of QStash publish
11	 * - All 5 steps preserved: close-gate, cancel-backfill, revoke-token, cleanup-cache, remove-resources
12	 */
13	
14	import { db } from "@db/app/client";
15	import {
16	  gatewayInstallations,
17	  gatewayLifecycleLogs,
18	  gatewayTokens,
19	  orgIntegrations,
20	} from "@db/app/schema";
21	import { decrypt } from "@repo/app-encryption";
22	import type { SourceType } from "@repo/app-providers";
23	import { getProvider } from "@repo/app-providers";
24	import { eq } from "@vendor/db";
25	import { parseError } from "@vendor/observability/error/next";
26	import { log } from "@vendor/observability/log/next";
27	import { getEncryptionKey } from "../../lib/encryption";
28	import { providerConfigs } from "../../lib/provider-configs";
29	import { inngest } from "../client";
30	
31	export const connectionLifecycle = inngest.createFunction(
32	  {
33	    id: "platform/connection.lifecycle",
34	    name: "Connection Lifecycle (Teardown)",
35	    retries: 3,
36	    concurrency: [
37	      // 1 teardown per connection at a time
38	      { limit: 1, key: "event.data.installationId" },
39	    ],
40	    timeouts: { start: "1m", finish: "5m" },
41	  },
42	  { event: "platform/connection.lifecycle" },
43	  async ({ event, step }) => {
44	    const {
45	      installationId,
46	      provider: providerName,
47	      correlationId,
48	    } = event.data;
49	
50	    // Step 1: Close the ingress gate — all guards check status === 'active',
51	    // so setting 'revoked' immediately blocks new requests.
52	    await step.run("close-gate", async () => {
53	      await db
54	        .update(gatewayInstallations)
55	        .set({ status: "revoked", updatedAt: new Date().toISOString() })
56	        .where(eq(gatewayInstallations.id, installationId));
57	
58	      await db.insert(gatewayLifecycleLogs).values({
59	        installationId,
60	        event: "gate_closed",
61	        fromStatus: "active",
62	        toStatus: "revoked",
63	        reason: "Ingress gate closed by teardown workflow",
64	        metadata: {
65	          step: "close-gate",
66	          workflowContext: "connection-lifecycle",
67	          triggeredBy: "system",
68	        },
69	      });
70	
71	      log.info("gate closed");
72	    });
73	
74	    // Step 2: Cancel any running backfill (best-effort, via Inngest event)
75	    await step.run("cancel-backfill", async () => {
76	      try {
77	        await inngest.send({
78	          name: "platform/backfill.run.cancelled",
79	          data: {
80	            installationId,
81	            correlationId,
82	          },
83	        });
84	        log.info("backfill cancellation sent");
85	      } catch (err) {
86	        log.warn("backfill cancellation failed (best-effort)", {
87	          error: parseError(err),
88	        });
89	      }
90	    });
91	
92	    // Step 3: Revoke token at provider (best-effort)
93	    await step.run("revoke-token", async () => {
94	      if (providerName === "github") {
95	        log.info("skipping token revocation (github uses on-demand JWTs)");
96	        return;
97	      }
98	
99	      const providerDef = getProvider(providerName as SourceType);
100	      const config = providerConfigs[providerName];
101	
102	      if (!config) {
103	        log.warn("provider not configured, skipping token revocation");
104	        return;
105	      }
106	
107	      const tokenRows = await db
108	        .select()
109	        .from(gatewayTokens)
110	        .where(eq(gatewayTokens.installationId, installationId))
111	        .limit(1);
112	
113	      const tokenRow = tokenRows[0];
114	      if (!tokenRow) {
115	        log.info("no token row found, skipping revocation");
116	        return;
117	      }
118	
119	      try {
120	        const auth = providerDef.auth;
121	        if (auth.kind === "oauth" && auth.revokeToken) {
122	          const decryptedToken = await decrypt(
123	            tokenRow.accessToken,
124	            getEncryptionKey()
125	          );
126	          await auth.revokeToken(config as never, decryptedToken);
127	        }
128	        log.info("token revoked");
129	      } catch (err) {
130	        log.warn("token revocation failed (best-effort)", {
131	          error: parseError(err),
132	        });
133	      }
134	    });
135	
136	    // Step 4: Disconnect org integrations and log resource disconnection.
137	    // For user-initiated disconnects the app-layer cascade may have already
138	    // set orgIntegrations.status → 'disconnected', but for health-check
139	    // triggers no cascade runs. We update unconditionally (idempotent).
140	    await step.run("disconnect-resources", async () => {
141	      const allResources = await db
142	        .select({ providerResourceId: orgIntegrations.providerResourceId })
143	        .from(orgIntegrations)
144	        .where(eq(orgIntegrations.installationId, installationId));
145	
146	      if (allResources.length > 0) {
147	        const now = new Date().toISOString();
148	        await db
149	          .update(orgIntegrations)
150	          .set({
151	            status: "disconnected",
152	            statusReason: "installation_revoked",
153	            updatedAt: now,
154	          })
155	          .where(eq(orgIntegrations.installationId, installationId));
156	      }
157	
158	      const resourceIdMap: Record<string, string> = {};
159	      for (const r of allResources) {
160	        resourceIdMap[r.providerResourceId] = "disconnected";
161	      }
162	
163	      await db.insert(gatewayLifecycleLogs).values({
164	        installationId,
165	        event: "resources_removed",
166	        fromStatus: "revoked",
167	        toStatus: "revoked",
168	        reason: `Disconnected ${allResources.length} linked resource(s) during teardown`,
169	        resourceIds: resourceIdMap,
170	        metadata: { step: "disconnect-resources", triggeredBy: "system" },
171	      });
172	
173	      log.info("resources disconnected", {
174	        count: allResources.length,
175	      });
176	    });
177	
178	    return { success: true, installationId };
179	  }
180	);

